@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1">
            <small class="text-muted">@Task.Assignee</small>
        </p>
        <span class="badge @PriorityClass me-2">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for adding a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@isSaving">
                @(isSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-secondary btn-sm" @onclick="OnCancel" disabled="@isSaving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="text-danger mt-1"><small>@errorMessage</small></div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }
    [Parameter, EditorRequired] public string ColumnStatus { get; set; } = "";

    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }

        isSaving = true;
        errorMessage = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            // If the task was created with a different status than our column, update it
            if (created.Status != ColumnStatus)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, ColumnStatus);
                created = created with { Status = ColumnStatus };
            }
            await OnTaskCreated.InvokeAsync(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }
}

@* A single Kanban column showing a header, task cards, and an optional add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => OnMoveLeft.InvokeAsync(task)"
                          OnMoveRight="() => OnMoveRight.InvokeAsync(task)" />
            }

            @if (showForm)
            {
                <AddTaskForm ColumnStatus="@Status"
                             TaskService="TaskService"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer p-2">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter, EditorRequired] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private bool showForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await OnSearchChanged.InvokeAsync(value);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar TotalCount="allTasks.Count"
                   TodoCount="TodoTasks.Count"
                   InProgressCount="InProgressTasks.Count"
                   DoneCount="DoneTasks.Count"
                   OverdueCount="OverdueCount" />

    <TaskSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Status="To Do"
                      Tasks="FilteredTodoTasks"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="task => MoveTask(task, \"In Progress\")"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />

        <KanbanColumn ColumnName="In Progress"
                      Status="In Progress"
                      Tasks="FilteredInProgressTasks"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="task => MoveTask(task, \"To Do\")"
                      OnMoveRight="task => MoveTask(task, \"Done\")"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />

        <KanbanColumn ColumnName="Done"
                      Status="Done"
                      Tasks="FilteredDoneTasks"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="task => MoveTask(task, \"In Progress\")"
                      OnTaskCreated="HandleTaskCreated"
                      TaskService="TaskService" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered lists by status (used for stats)
    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private int OverdueCount => allTasks.Count(t => t.DueDate < DateTime.Today);

    // Filtered lists (used for display in columns)
    private List<TaskItem> FilteredTodoTasks => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgressTasks => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDoneTasks => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }
}

